#include <stdio.h>
#define ROWS 3
#define COLUMNS 4
int main() {
 int matrix[ROWS][COLUMNS];
 for (int i = 0; i < ROWS; i++) {
 for (int j = 0; j < COLUMNS; j++) {
 matrix[i][j] = i * j;
 }
 }
 for (int i = 0; i < ROWS; i++) {
 for (int j = 0; j < COLUMNS; j++) {
 printf("%d ", matrix[i][j]);
 }
 printf("\n");
 }
 return 0;
}
